mapper.select:
SELECT entry.id, entry.title, entry.content from admin_entry entry



        entry.id > #{timestamp}



        AND entry.date >= #{articleDate}



order by entry.id

select entry.id, entry.title, entry.author, entry.content, entry.link, entry.date, entry.tags, aTranslations.content_zh as contentZh, aTranslations.title_zh as titleZh, aTranslations.content_en as cleanedContentEn, feed.name as feedName, feed.priority as feedPriority, feed.description as feedDescription, feed.url as feedUrl, feed.website as feedWebsite, entry.id_feed as feedId, aCategory.id as categoryId, aCategory.name as categoryName from admin_entry entry left join article_translations aTranslations on aTranslations.article_create_date = entry.id left join admin_feed feed ON entry.id_feed = feed.id left join admin_category aCategory ON feed.category = aCategory.id
AND entry.date >= #{startTime}
AND entry.date <= #{endTime}

